var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"성야의...... 저주가...... 다가온다...... 다가온다......","JPN":"聖夜の……呪いが……やってくる……やってくる……","ENG":"The Curse... of the Holy Night... is coming... It's coming...","TWN":"耶誕的……詛咒……來了……來了……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"과도한 충격으로 시스템이 다운됩니다. 관리자를 통해 문제를 해결하십시오.","JPN":"過度の衝撃でシステムがダウンします。管理者より問題を解決してください。","ENG":"Too much shock. The system is now shutting down. Please contact your administrator for assistance.","TWN":"因強烈衝擊系統癱瘓，請通過管理者解決問題。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그 로봇 사장한테 뭐 특별한 볼일이라도 있어?","JPN":"そのロボット社長に、何か用でもあるわけ？","ENG":"Why do you need your robot boss?","TWN":"那個機器人老闆有什麼用？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭔진 몰라도 서둘러. 저 녀석들이 포위망을 점점 좁히고 있으니까.","JPN":"何をするつもりか知らないけど、とりあえず急いで。\\nあいつらの包囲網がどんどん狭まってる。","ENG":"Whatever it is, hurry. They're closing on us.","TWN":"快點行動吧，他們的包圍圈越來越小了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......이상하다고 생각하지 않아요?","JPN":"……おかしいと思いませんか？","ENG":"Don't you think this is strange?","TWN":"……妳不覺得很奇怪嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이상하기는 이 멍청한 파티 초대장 받을 때부터 이상했지.","JPN":"おかしいのは、このふざけたパーティーの招待状をもらった時からよ。","ENG":"It is strange. It has been all along, since I received the invitation to this stupid party.","TWN":"我收到這個愚蠢的邀請函的時候就覺得很奇怪了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"전부 다 이상해서 멀쩡한 게 이상할 정도야.","JPN":"全部おかしすぎて、普通なものが逆におかしく思えるくらいよ。","ENG":"Everything is so strange that it almost feels normal.","TWN":"奇怪的連正常的東西都看起來很奇怪。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런 거 말고요.","JPN":"そうじゃありません。","ENG":"I'm talking about something else.","TWN":"我不是說那些。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"애초에 이런 불합리한 일이 벌어질 리가 없어요.","JPN":"そもそも、こんな不合理的なことが起きるはずがないんです。","ENG":"I don't believe one person can create such an inexplicable phenomenon.","TWN":"這種不合理的事情根本就是不可能發生的。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"공간이 왜곡되고 조각상이 날뛰는 건 그렇다고 쳐요.","JPN":"空間が歪曲され、彫刻像が暴れるのはいいとして。","ENG":"Maybe she can warp space and animate sculptures.","TWN":"空間扭曲和雕像發瘋就算了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 주시윤 선배나 제이크 씨는 호락호락한 사람들이 아니에요.","JPN":"先輩やジェイクさんはそんな簡単な相手ではありません。","ENG":"But what about Shiyoon and Jake? They're not easy prey.","TWN":"但周時雲前輩和傑克可不是簡單的人。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"알렉스 씨가 아무리 강해도 그 둘을 소리소문 없이 제압해서 꼭두각시로 쓸 수 있을까요?","JPN":"アレックスさんがいくら強くても、あの二人を静かに制圧して、操り人形にすることができるでしょうか？","ENG":"No matter how strong Alex is, there's no way she could dominate and control them so quietly and easily.","TWN":"雅蕾克絲即使很強，但怎麼可能悄無聲息地就讓他們成為了傀儡？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"하긴......","JPN":"……確かに。","ENG":"Maybe you're right.","TWN":"也是……"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"다른 건 몰라도 버터맨이 다른 사람한테 조종당한다는 건 상상이 좀 안 되네.","JPN":"他はわからないけど、バターマンが他の人に操られるなんて想像できないもん。","ENG":"I don't know about the others, but I can hardly imagine Sleazeball being controlled by someone else.","TWN":"其他的我倒是不知道，油膩男被人控制我就無法理解了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"무엇보다 말이죠, 선배는 전자기 펄스로 억제됐잖아요?","JPN":"何よりも、先輩は電磁パルスで抑制されましたよね？","ENG":"Most of all, we incapacitated Shiyoon with EMP.","TWN":"而且，前輩被電磁脈衝控制住了不是嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런데 무게 잡을 때마다 스파크가 튀는 제이크 씨는 왜 계속 저 상태일까요?","JPN":"でも、力を加える度に火花が出るジェイクさんは、なぜあの状態なのでしょうか？","ENG":"But what about Jake, the man who always crackles with lightning? Why is he still in that state?","TWN":"但每次爆發如雷又愛裝嚴肅的傑克，怎麼仍舊是那種狀態呢？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};